// Ported from Mode_Controller.txt — layer visibility + AudioMute side effects
// modeState.currentMode drives Dashboard UI conditional visibility bindings.
// Audio mute state mirrors AudioMute.Boolean assignments in the original Lua.
const projector = global.get('projector');
const devices = global.get('devices');
const modeState = global.get('modeState');

const modeName = msg.payload.mode;  // 'classroom' | 'assembly' | 'production'
const rearIp = devices.projectors.rear.ip;

(async () => {
    try {
        console.log(`[setMode] Switching to mode: ${modeName}`);
        modeState.currentMode = modeName;

        if (modeName === 'classroom') {
            // AudioMute.Boolean = false in original — rear projector audio un-muted
            console.log('[setMode] classroom: un-muting rear projector audio');
            await projector.setAudioMute(rearIp, false);
        } else if (modeName === 'assembly') {
            // AudioMute.Boolean = true in original
            console.log('[setMode] assembly: muting rear projector audio');
            await projector.setAudioMute(rearIp, true);
        } else if (modeName === 'production') {
            // AudioMute.Boolean = true in original
            console.log('[setMode] production: muting rear projector audio');
            await projector.setAudioMute(rearIp, true);
        } else {
            node.warn(`[setMode] Unknown mode: "${modeName}"`);
        }

        console.log(`[setMode] Mode is now: ${modeName}`);
        msg.payload = { success: true, mode: modeName };
        node.send(msg);
    } catch (err) {
        node.error('[setMode] ' + err.message, msg);
    }
})();

return null;

// Ported from Mode_Controller.txt — PowerButton / full shutdown sequence
//
// The 3-second delay (matching Timer.CallAfter(3, ...) in original Q-SYS Lua)
// gives projectors time to begin their shutdown sequence before the UI
// visually returns to the welcome/startup screen. Do not remove.
const projector = global.get('projector');
const devices = global.get('devices');
const modeState = global.get('modeState');

const { left, right, rear } = devices.projectors;

(async () => {
    try {
        console.log('[powerButtonPressed] Powering off all projectors (mirrors powerAllOff)');
        // All three fire concurrently — same behaviour as powerAllOff in flow 03
        await Promise.all([
            projector.powerOff(left.ip).then(() => { modeState.projectorPower.left = false; }),
            projector.powerOff(right.ip).then(() => { modeState.projectorPower.right = false; }),
            projector.powerOff(rear.ip).then(() => { modeState.projectorPower.rear = false; }),
        ]);

        console.log('[powerButtonPressed] Projectors shutting down — waiting 3s before clearing mode');
        await new Promise(resolve => setTimeout(resolve, 3000));

        modeState.currentMode = null;
        console.log('[powerButtonPressed] Mode cleared — UI returning to welcome state');
        msg.payload = { success: true };
        node.send(msg);
    } catch (err) {
        node.error('[powerButtonPressed] ' + err.message, msg);
    }
})();

return null;
